import face_recognition
from flask import Flask, request, jsonify
from sklearn.model_selection import train_test_split
from sklearn.preprocessing import StandardScaler
from sklearn.svm import SVC
from sklearn.metrics import accuracy_score
from PIL import Image
import numpy as np
import os
import pickle

app = Flask(__name__)

# Load employee photos and extract face encodings
employee_photos = []
for file in os.listdir('employee_photos'):
    image = face_recognition.load_image_file(os.path.join('employee_photos', file))
    encoding = face_recognition.face_encodings(image)[0]
    employee_photos.append(encoding)

# Train model on employee photos
X_train, X_test, y_train, y_test = train_test_split(employee_photos, [i for i in range(len(employee_photos))], test_size=0.2, random_state=42)
scaler = StandardScaler()
X_train_scaled = scaler.fit_transform(X_train)
model = SVC(kernel='rbf', probability=True, C=1)
model.fit(X_train_scaled, y_train)

# Save model to file
with open('security_model.pkl', 'wb') as f:
    pickle.dump(model, f)

@app.route('/recognize', methods=['POST'])
def recognize():
    # Get image from request
    image = request.files['image']

    # Extract face encodings from image
    image_encoding = face_recognition.face_encodings(face_recognition.load_image_file(image))[0]

    # Scale encoding to match training data
    scaled_encoding = scaler.transform([image_encoding])

    # Make prediction and get confidence scores
    predictions = model.predict(scaled_encoding)
    confidences = model.decision_function(scaled_encoding)

    # Get detailed probability distribution over all known faces
    probabilities = model.predict_proba(scaled_encoding)

    return jsonify({
        'predictions': [int(prediction) for prediction in predictions],
        'confidences': [float(confidence) for confidence in confidences],
        'probabilities': [[float(probability) for probability in row] for row in probabilities]
    })

if __name__ == '__main__':
    app.run(debug=True)